    output::{file_name::Absolute, time::TimeFormat},
};

const SORT_FIELDS_HELP: &str = "[default: name] [possible values:
  name, Name, .name, .Name, ext, ext, created,
  date, age, accessed, changed,
  size, inode, type, none]";

