    /// The style to paint a directory that has a filesystem mounted on it.
    fn mount_point(&self) -> Style;

    fn colour_file(&self, file: &File<'_>) -> Style;

    fn style_override(&self, file: &File<'_>) -> Option<FileNameStyle>;
}

